import networkx as nx
EST = [max(tau_min[i], min(v[k] + d0[k][i] for k in range(K))) for i in range(N)]
A_minus = {(i, j) for i in range(N) for j in range(N) if EST[i] + d[i][i] + d[i][j] > tau_max[j]}
G = nx.Graph()
G.add_nodes_from(range(N))
for i in range(N):
    for j in range(i + 1, N):
        if (i, j) in A_minus and (j, i) in A_minus:
            G.add_edge(i, j)
for C in nx.find_cliques(G):
    K_C = {k for k in range(K) if any(v[k] + d0[k][i] <= tau_max[i] for i in C)}
    if len(C) > len(K_C):
        model.addConstr(gp.quicksum(x[K + i, K + i] for i in C) >= len(C) - len(K_C))
